def traverse(self, mode='inorder'):
    """Default inorder; supports 'preorder', 'postorder'"""
    if mode == 'inorder':
        return self._inorder(self.root)
    elif mode == 'preorder':
        return self._preorder(self.root)
    elif mode == 'postorder':
        return self._postorder(self.root)
```

